<template>
  <div class="bg-eerie-black rounded-lg text-gray-100">
    <section class="bg-gray-700 p-4 md:p-6 rounded-lg shadow-md max-w-lg mx-auto">
      <h2 class="text-xl md:text-2xl font-bold text-gray-100 mb-4">Einstellungen importieren</h2>
      <p class="text-sm text-gray-400 mb-4">Importiere Thema und App-Einstellungen aus einer JSON-Datei. Keine Aufgabendaten werden importiert.</p>
      <div class="flex flex-col gap-3 md:gap-4">
        <label for="importFile" class="btn-import cursor-pointer">
          <Icon icon="heroicons:arrow-up-tray-20-solid" class="w-5 h-5 md:w-6 md:h-6 mr-2 md:mr-3" />
          Einstellungen importieren
        </label>
        <input
          id="importFile"
          type="file"
          accept=".json"
          class="hidden"
          @change="importSettings"
        >
      </div>
    </section>
  </div>
</template>

<script setup lang="ts">
import { Icon } from '@iconify/vue';
import { useUserSettings } from '~/composables/useUserSettings';

definePageMeta({ title: 'Import' });

const router = useRouter();
const { importSettings: doImport, userSettings } = useUserSettings();

const importSettings = (event: Event) => {
  const target = event.target as HTMLInputElement;
  const file = target.files?.[0];
  if (!file) return;

  const reader = new FileReader();
  reader.onload = (e) => {
    try {
      const json = e.target?.result as string;
      if (doImport(json)) {
        const theme = userSettings.value.theme.selectedTheme;
        if (theme && typeof document !== 'undefined') {
          document.documentElement.setAttribute('data-theme', theme);
        }
        alert('Einstellungen erfolgreich importiert!');
        router.push('/settings');
      } else {
        alert('Ungültige JSON-Datei.');
      }
    } catch {
      alert('Fehler beim Lesen der JSON-Datei.');
    }
    target.value = '';
  };
  reader.readAsText(file);
};
</script>
